async (page) => {
  // 1. Open inventory panel
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(800);
  // 2. Click the item slot (slot 0 = Bronze Axe)
  await page.evaluate((idx) => {
    const slots = document.querySelectorAll('.item-slot');
    if (slots[idx]) slots[idx].click();
  }, 0);
  await page.waitForTimeout(800);
  // 3. Click the equip button in the popup
  await page.evaluate(() => {
    const btn = document.querySelector('.action-equip');
    if (btn) btn.click();
  });
  await page.waitForTimeout(500);
  // 4. Close inventory panel
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(500);
  // 5. Set attack style to Hack (index 0)
  await page.evaluate(() => window.game.player.setAttackStyle(0));
  await page.waitForTimeout(300);
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return 'Equipped Bronze Axe and set Hack attack style';
}

async (page) => {
  const result = await page.evaluate(() => {
    const player = window.game?.player;
    if (!player) return 'no player';
    return JSON.stringify({
      weaponKey: player.weaponKey || player.weapon?.key,
      weapon: player.weapon ? {key: player.weapon.key, name: player.weapon.name} : null,
      equipment: player.equipment ? Object.keys(player.equipment).reduce((acc, k) => {
        const eq = player.equipment[k];
        acc[k] = eq ? {key: eq.key, name: eq.name} : null;
        return acc;
      }, {}) : null
    });
  });
  return result;
}

async (page) => {
