async (page) => {
  const chopNearestTree = async () => {
    const tree = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const t = gs.nearby_entities?.find(e => e.type === 10 && e.name === 'Oak' && e.on_screen && e.click_x);
      return t ? {cx: t.click_x, cy: t.click_y} : null;
    });
    if (tree) {
      await page.evaluate(({x, y}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
      }, {x: tree.cx, y: tree.cy});
    }
    return !!tree;
  };

  // Chop until 10 logs
  for (let i = 0; i < 15; i++) {
    await chopNearestTree();
    await page.waitForTimeout(4000);

    const logs = await page.evaluate(() => {
      const gs = window.__latestGameState;
      return gs.inventory?.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0) || 0;
    });

    if (logs >= 10) break;
  }

  const result = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const logs = gs.inventory?.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0) || 0;
    return JSON.stringify({logs, foresting: gs.quests?.find(q => q.key === 'foresting'), pos: gs.player_position});
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return result;
}

async (page) => {
  const chopNearestTree = async () => {
    const tree = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const t = gs.nearby_entities?.find(e => e.type === 10 && e.name === 'Oak' && e.on_screen && e.click_x);
      return t ? {cx: t.click_x, cy: t.click_y} : null;
    });
    if (tree) {
      await page.evaluate(({x, y}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
      }, {x: tree.cx, y: tree.cy});
    }
    return !!tree;
  };

  for (let i = 0; i < 15; i++) {
    await chopNearestTree();
    await page.waitForTimeout(4000);

    const {logs, stage} = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const logs = gs.inventory?.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0) || 0;
      const foresting = gs.quests?.find(q => q.key === 'foresting');
      return {logs, stage: foresting?.stage};
    });

    // If stage changed to 2, we delivered the logs already (quest advances automatically)
    if (stage >= 2 || logs >= 10) break;
  }

  const result = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const logs = gs.inventory?.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0) || 0;
    return JSON.stringify({
      logs,
      foresting: gs.quests?.find(q => q.key === 'foresting'),
      pos: gs.player_position
    });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return result;
}

