async (page) => {
  // Rotate between different trees
  const treePositions = [
    {cx: 696, cy: 384},   // 10-37901111 at 219,112
    {cx: 1128, cy: 336},  // 10-73957102 at 228,111
    {cx: 984, cy: 624},   // 10-94799149 at 225,117
    {cx: 456, cy: 672},   // 10-12313156 at 214,118
  ];

  let treeIdx = 0;
  let logs = 2; // starting with 2

  for (let i = 0; i < 30 && logs < 10; i++) {
    const pos = treePositions[treeIdx % treePositions.length];
    treeIdx++;

    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    }, {x: pos.cx, y: pos.cy});

    await page.waitForTimeout(4000);

    logs = await page.evaluate(() => {
      const gs = window.__latestGameState;
      return gs.inventory?.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0) || 0;
    });
  }

  const result = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const logs = gs.inventory?.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0) || 0;
    return JSON.stringify({logs, stage: gs.quests?.find(q => q.key === 'foresting')?.stage, pos: gs.player_position});
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return result;
}

async (page) => {
  // Kill any nearby mobs first, then chop more aggressively
  // Check for mobs attacking me
  const mobInfo = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const mob = gs.nearby_entities?.find(e => e.type === 3 && e.distance <= 2 && e.on_screen && e.click_x);
    const tree = gs.nearby_entities?.find(e => e.type === 10 && e.name === 'Oak' && e.on_screen && e.click_x);
    return {mob: mob ? {cx: mob.click_x, cy: mob.click_y, name: mob.name} : null, tree: tree ? {cx: tree.click_x, cy: tree.click_y} : null, logs: gs.inventory?.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0) || 0};
  });

  // Chop the tree with frequent clicks (less wait between clicks)
  if (mobInfo.tree) {
    // Click tree many times quickly
    for (let i = 0; i < 15; i++) {
      const tree = await page.evaluate(() => {
        const gs = window.__latestGameState;
        const t = gs.nearby_entities?.find(e => e.type === 10 && e.name === 'Oak' && e.on_screen && e.click_x);
        return t ? {cx: t.click_x, cy: t.click_y} : null;
      });
      if (tree) {
        await page.evaluate(({x, y}) => {
          document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
        }, {x: tree.cx, y: tree.cy});
      }
      await page.waitForTimeout(1500); // Shorter wait - 1.5s instead of 4s

      const logs = await page.evaluate(() => {
        const gs = window.__latestGameState;
        return gs.inventory?.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0) || 0;
      });
      if (logs >= 10) break;
    }
  }

  const result = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const logs = gs.inventory?.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0) || 0;
    return JSON.stringify({logs, hp: gs.player_stats?.hp, pos: gs.player_position, stage: gs.quests?.find(q=>q.key==='foresting')?.stage});
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return result;
}

