async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Kill rats and grind toward Blacksmith
  let strLevel = 4;
  let kills = 0;

  for (let i = 0; i < 20 && strLevel < 8; i++) {
    const state = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const rats = gs.nearby_entities?.filter(e => e.name === 'Rat' && e.on_screen && e.click_x);
      const blacksmith = gs.nearby_entities?.find(e => e.name === 'Blacksmith');
      return {
        pos: gs.player_position,
        hp: gs.player_stats?.hp,
        str: window.game?.player?.skills?.[6]?.level,
        rat: rats?.[0] ? {cx: rats[0].click_x, cy: rats[0].click_y, hp: rats[0].hp, dist: rats[0].distance} : null,
        blacksmith: blacksmith ? {dist: blacksmith.distance, cx: blacksmith.click_x, cy: blacksmith.click_y, on_screen: blacksmith.on_screen} : null
      };
    });

    strLevel = state.str || 4;

    if (state.hp < 40) {
      // Warp to heal
      await page.evaluate(() => { window.game.menu.warp.show(); setTimeout(() => document.getElementById('warp0').click(), 500); });
      await page.waitForTimeout(3000);
      continue;
    }

    if (state.rat) {
      await click(state.rat.cx, state.rat.cy);
      await page.waitForTimeout(5000);
      kills++;
    } else if (state.blacksmith?.on_screen && state.blacksmith?.cx) {
      // Found blacksmith - go there
      await click(state.blacksmith.cx, state.blacksmith.cy);
      await page.waitForTimeout(3000);
      break;
    } else {
      // Walk south toward blacksmith
      await click(700, 600);
      await page.waitForTimeout(2000);
    }
  }

  const finalState = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const blacksmith = gs.nearby_entities?.find(e => e.name === 'Blacksmith');
    return JSON.stringify({
      pos: gs.player_position,
      hp: gs.player_stats?.hp,
      str: window.game?.player?.skills?.[6]?.level,
      def: window.game?.player?.skills?.[7]?.level,
      kills_approx: true,
      blacksmith: blacksmith ? {dist: blacksmith.distance, cx: blacksmith.click_x, cy: blacksmith.click_y, on_screen: blacksmith.on_screen, id: blacksmith.id} : null
    });
  });
  return finalState;
}

