async (page) => {
  // Search the game's entity registry for any Old Lady/Grandma NPC
  const found = await page.evaluate(() => {
    try {
      // Try to find entities in the game object
      const entities = window.game?.entities?.grids?.grid;
      const results = [];
      if (entities) {
        for (const row of entities) {
          if (!row) continue;
          for (const cell of row) {
            if (!cell) continue;
            for (const [id, entity] of Object.entries(cell)) {
              const name = entity?.name || entity?.id;
              if (name && (name.toLowerCase().includes('old') || name.toLowerCase().includes('grand') || name.toLowerCase().includes('lady') || name.toLowerCase().includes('mama'))) {
                results.push({ id, name, x: entity.gridX, y: entity.gridY });
              }
            }
          }
        }
      }
      return results;
    } catch(e) {
      return `Error: ${e.message}`;
    }
  });

  return JSON.stringify(found, null, 2);
}

