async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  let lastPos = { x: 255, y: 146 };
  let stuckCount = 0;

  for (let i = 0; i < 20; i++) {
    await click(640, 700);
    await page.waitForTimeout(3000);

    const state = await page.evaluate(() => window.__latestGameState);
    const pos = state?.player_position;
    const hp = state?.player_stats?.hp;
    const maxHp = state?.player_stats?.max_hp;

    // Heal if needed
    if (hp < maxHp * 0.5) {
      await page.evaluate(() => window.game.menu.getInventory().selectEdible(4));
      await page.waitForTimeout(400);
    }

    // Check for quest NPC (Wife)
    const questNPC = (state?.nearby_entities || []).find(e => e.quest_npc);
    if (questNPC) {
      return { found: questNPC, pos, hp };
    }

    // Check stuck
    if (pos?.x === lastPos?.x && pos?.y === lastPos?.y) {
      stuckCount++;
      if (stuckCount >= 2) {
        // Try slightly different direction
        await click(700, 700);
        await page.waitForTimeout(2000);
        stuckCount = 0;
      }
    } else {
      stuckCount = 0;
      lastPos = pos;
    }

    if (pos?.y >= 225) break;
  }

  const state = await page.evaluate(() => window.__latestGameState);
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return { pos: state?.player_position, hp: state?.player_stats };
}

